const games = [
  { appId: '1091500', name: 'Cyberpunk 2077',       targetPrice: 20 },
  { appId: '3595230', name: 'COD: MW2 (2022)',       targetPrice: 15 },
  { appId: '3595270', name: 'COD: MW3 (2023)',       targetPrice: 15 },
  { appId: '2239550', name: 'Watch Dogs Legion',     targetPrice: 10 },
  { appId: '2668510', name: 'Red Dead Redemption 1', targetPrice: 10 },
];

const data = $input.first().json;
const deals = [];

for (const game of games) {
  const appData = data[game.appId];

  if (!appData || !appData.success) continue;

  const priceData = appData.data?.price_overview;
  if (!priceData) continue;

  const currentPrice  = priceData.final / 100;
  const originalPrice = priceData.initial / 100;
  const discount      = priceData.discount_percent;

  const hitsTarget = game.targetPrice === 0
    ? discount > 0
    : currentPrice <= game.targetPrice;

  if (hitsTarget) {
    deals.push({
      name: game.name,
      currentPrice,
      originalPrice,
      discount,
      targetPrice: game.targetPrice,
      line: `🎮 *${game.name}*\n` +
            `   💰 ~~$${originalPrice}~~ → *$${currentPrice}*\n` +
            `   🏷️ ${discount}% OFF (your target: $${game.targetPrice})`
    });
  }
}

const count = deals.length;
const lines = deals.map(d => d.line).join('\n\n');

const message = count > 0
  ? `🔥 *Steam Price Alert!*\n${count} game${count > 1 ? 's are' : ' is'} on sale:\n\n${lines}\n\n👉 [Open Steam Store](https://store.steampowered.com)`
  : '';

// Always return a valid item — use hasDeal flag to control flow after
return [{ json: { message, dealCount: count, hasDeal: count > 0 } }];
